import clsx from 'clsx';

import { container } from './TooltipHeader.sty.js';
import { Divider } from '../../../../../../layouts/divider/Divider.js';
import { Flex } from '../../../../../../layouts/flex/Flex.js';
import type { TooltipHeaderProps } from '../../types/tooltip.js';
import { iterateHeaderSlots } from '../../utils/iterate-header-slots.js';
import { TooltipItem } from '../TooltipItem/TooltipItem.js';

export const HEADER_SECTION_NAME = 'header';

export const TooltipHeader = (props: TooltipHeaderProps) => {
  const { withoutDivider, children, ...rest } = props;
  const { header, subHeader } = iterateHeaderSlots(children);

  return (
    <Flex
      className={clsx(
        container({ withBorder: !withoutDivider }),
        HEADER_SECTION_NAME,
      )}
      {...rest}
    >
      <Flex alignItems="center" gap={0}>
        {header}
      </Flex>

      <Flex alignItems="center" gap={0}>
        <TooltipItem>{subHeader}</TooltipItem>
      </Flex>

      {withoutDivider ? null : <Divider orientation="horizontal" />}
    </Flex>
  );
};

TooltipHeader['displayName'] = 'TooltipHeader';
